   274→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   275→func convertTools(req *model.LLMRequest) []chatTool {
   276→	if req.Config == nil || len(req.Config.Tools) == 0 {
   277→		return nil
   278→	}
   279→
   280→	var tools []chatTool
   281→	for _, t := range req.Config.Tools {
   282→		for _, fd := range t.FunctionDeclarations {
   283→			ct := chatTool{
   284→				Type: "function",
   285→				Function: chatFunction{
   286→					Name:        fd.Name,
   287→					Description: fd.Description,
   288→				},
   289→			}
   290→			if fd.Parameters != nil {
   291→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   292→			}
   293→			tools = append(tools, ct)
   294→		}
   295→	}
   296→	return tools
   297→}
   298→
   299→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   300→// the OpenAI function parameters format (JSON Schema).
   301→func schemaToMap(s *genai.Schema) map[string]any {
   302→	m := map[string]any{}
   303→	if s.Type != "" {
   304→		m["type"] = string(s.Type)
   305→	}
   306→	if s.Description != "" {
   307→		m["description"] = s.Description
   308→	}
   309→	if len(s.Enum) > 0 {
   310→		m["enum"] = s.Enum
   311→	}
   312→	if s.Items != nil {
   313→		m["items"] = schemaToMap(s.Items)
   314→	}
   315→	if len(s.Properties) > 0 {
   316→		props := map[string]any{}
   317→		for k, v := range s.Properties {
   318→			props[k] = schemaToMap(v)
   319→		}
   320→		m["properties"] = props
   321→	}
   322→	if len(s.Required) > 0 {
   323→		m["required"] = s.Required
   324→	}
   325→	return m
   326→}
   327→
   328→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   329→func convertResponse(resp *chatResponse) *model.LLMResponse {
   330→	llmResp := &model.LLMResponse{
   331→		TurnComplete: true,
   332→	}
   333→
   334→	if len(resp.Choices) == 0 {
   335→		llmResp.Content = genai.NewContentFromText("", "model")
   336→		return llmResp
   337→	}
   338→
   339→	choice := resp.Choices[0]
   340→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   341→
   342→	content := &genai.Content{Role: "model"}
   343→
   344→	// Text content.
   345→	if choice.Message.Content != "" {
   346→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   347→	}
   348→
   349→	// Tool calls.
   350→	for _, tc := range choice.Message.ToolCalls {
   351→		var args map[string]any
   352→		if tc.Function.Arguments != "" {
   353→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   354→		}
   355→		content.Parts = append(content.Parts, &genai.Part{
   356→			FunctionCall: &genai.FunctionCall{
   357→				ID:   tc.ID,
   358→				Name: tc.Function.Name,
   359→				Args: args,
   360→			},
   361→		})
   362→	}
   363→
   364→	llmResp.Content = content
   365→
   366→	if resp.Usage != nil {
   367→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   368→			PromptTokenCount:     resp.Usage.PromptTokens,
   369→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   370→			TotalTokenCount:      resp.Usage.TotalTokens,
   371→		}
   372→	}
   373→
   374→	return llmResp
   375→}
   376→
   377→func mapRole(role string) string {
   378→	switch role {
   379→	case "model":
   380→		return "assistant"
   381→	default:
   382→		return role
   383→	}
   384→}
   385→
   386→func mapFinishReason(reason string) genai.FinishReason {
   387→	switch reason {
   388→	case "stop":
   389→		return genai.FinishReasonStop
   390→	case "length":
   391→		return genai.FinishReasonMaxTokens
   392→	case "tool_calls":
   393→		return genai.FinishReasonStop
   394→	case "content_filter":
   395→		return genai.FinishReasonSafety
   396→	default:
   397→		return genai.FinishReasonOther
   398→	}
   399→}
