   133→// --- request/response conversion ---
   134→
   135→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   136→	msgs := convertContents(req)
   137→	tools := convertTools(req)
   138→
   139→	chatReq := chatRequest{
   140→		Model:    m.name,
   141→		Messages: msgs,
   142→		Tools:    tools,
   143→		Stream:   false,
   144→	}
   145→
   146→	if req.Config != nil {
   147→		chatReq.Temperature = req.Config.Temperature
   148→		chatReq.TopP = req.Config.TopP
   149→		if req.Config.MaxOutputTokens > 0 {
   150→			chatReq.MaxTokens = req.Config.MaxOutputTokens
   151→		}
   152→		if len(req.Config.StopSequences) > 0 {
   153→			chatReq.Stop = req.Config.StopSequences
   154→		}
   155→	}
   156→
   157→	body, err := json.Marshal(chatReq)
   158→	if err != nil {
   159→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   160→	}
   161→
   162→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/chat/completions", bytes.NewReader(body))
   163→	if err != nil {
   164→		return nil, fmt.Errorf("openai: create http request: %w", err)
   165→	}
   166→	httpReq.Header.Set("Content-Type", "application/json")
   167→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   168→
   169→	httpResp, err := m.client.Do(httpReq)
   170→	if err != nil {
   171→		return nil, fmt.Errorf("openai: http request: %w", err)
   172→	}
   173→	defer httpResp.Body.Close()
   174→
   175→	respBody, err := io.ReadAll(httpResp.Body)
   176→	if err != nil {
   177→		return nil, fmt.Errorf("openai: read response: %w", err)
   178→	}
   179→
   180→	if httpResp.StatusCode != http.StatusOK {
   181→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   182→	}
   183→
   184→	var chatResp chatResponse
   185→	if err := json.Unmarshal(respBody, &chatResp); err != nil {
   186→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   187→	}
   188→
   189→	if chatResp.Error != nil {
   190→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   191→			chatResp.Error.Message, chatResp.Error.Type, chatResp.Error.Code)
   192→	}
   193→
   194→	return convertResponse(&chatResp), nil
   195→}
