   113→// generateStream returns a stream of responses from the model.
   114→func (m *geminiModel) generateStream(ctx context.Context, req *model.LLMRequest) iter.Seq2[*model.LLMResponse, error] {
   115→	aggregator := llminternal.NewStreamingResponseAggregator()
   116→
   117→	return func(yield func(*model.LLMResponse, error) bool) {
   118→		for resp, err := range m.client.Models.GenerateContentStream(ctx, m.name, req.Contents, req.Config) {
   119→			if err != nil {
   120→				yield(nil, err)
   121→				return
   122→			}
   123→			for llmResponse, err := range aggregator.ProcessResponse(ctx, resp) {
   124→				if !yield(llmResponse, err) {
   125→					return // Consumer stopped
   126→				}
   127→			}
   128→		}
   129→		if closeResult := aggregator.Close(); closeResult != nil {
   130→			yield(closeResult, nil)
   131→		}
   132→	}
   133→}
